const fs = require('fs');
const path = require('path');
const Joi = require('joi');
const logger = require('../../../common/logger');

let cachedProblems;

const MAX_LIMIT = 50;

/**
 * Normalize tags filter into a lowercase array.
 * @param {string|Array<string>} rawTags
 * @returns {Array<string>}
 */
function normalizeTags(rawTags) {
  if (rawTags === undefined || rawTags === null) {
    return [];
  }
  if (Array.isArray(rawTags)) {
    return rawTags.map(t => String(t).toLowerCase());
  }
  if (typeof rawTags === 'string') {
    return rawTags.split(',').map(t => t.trim().toLowerCase()).filter(t => t.length > 0);
  }
  return [];
}

/**
 * Filter problems by tags.
 * @param {Array<Object>} problems
 * @param {Array<string>} tags
 * @returns {Array<Object>}
 */
function filterByTags(problems, tags) {
  if (!tags || tags.length === 0) return problems;
  return problems.filter(problem => {
    if (!problem.tags || !Array.isArray(problem.tags)) return false;
    const problemTagsLower = problem.tags.map(t => t.toLowerCase());
    return tags.every(tag => problemTagsLower.includes(tag));
  });
}

/**
 * Get problems with optional filters.
 * @param {Object} filters
 * @param {number} filters.difficulty
 * @param {number} filters.limit
 * @param {string|Array<string>} filters.tags
 * @returns {Object} { problems: Array, metadata: Object }
 */
function getProblems(filters) {
  if (!cachedProblems) {
    // Load problems from JSON file once
    const problemsPath = path.join(__dirname, '../../data/problems.json');
    const raw = fs.readFileSync(problemsPath, 'utf8');
    cachedProblems = JSON.parse(raw);
  }

  let problems = cachedProblems;

  // Filter by difficulty if provided
  if (filters.difficulty !== undefined && filters.difficulty !== null) {
    problems = problems.filter(p => p.difficulty === filters.difficulty);
  }

  // Normalize and filter by tags
  const normalizedTags = normalizeTags(filters.tags);
  problems = filterByTags(problems, normalizedTags);
